            id: 'symbol:src/app.ts:activate',
            name: 'activate',
            kind: 'function',
            filePath: 'src/app.ts',
            signature: '(): void',
            range: { startLine: 1, endLine: 3 },
          },
        ],
        relations: [
          {
            kind: 'call',
            sourceId: 'core:treesitter',
            fromFilePath: 'src/app.ts',
            toFilePath: 'src/lib.ts',
            fromSymbolId: 'symbol:src/app.ts:activate',
            toSymbolId: 'symbol:src/lib.ts:boot',
          },
        ],
      }],
      ['src/lib.ts', {
        filePath: 'src/lib.ts',
        symbols: [
          {
