import { describe, expect, it } from 'vitest';
import {
  createExportFilePathResolver,
  sortByFilePath,
} from '../../../../../src/extension/export/symbols/build/paths';

describe('extension/export/symbols/build/paths', () => {
  it('sorts file-backed items by file path without mutating the input array', () => {
    const input = [
      { filePath: 'src/z.ts', id: 'z' },
      { filePath: 'src/a.ts', id: 'a' },
      { filePath: 'src/m.ts', id: 'm' },
    ];

    expect(sortByFilePath(input)).toEqual([
      { filePath: 'src/a.ts', id: 'a' },
      { filePath: 'src/m.ts', id: 'm' },
      { filePath: 'src/z.ts', id: 'z' },
    ]);
    expect(input).toEqual([
      { filePath: 'src/z.ts', id: 'z' },
      { filePath: 'src/a.ts', id: 'a' },
      { filePath: 'src/m.ts', id: 'm' },
    ]);
  });

  it('resolves exact export file paths after normalizing path separators', () => {
    const resolveFilePath = createExportFilePathResolver([
      'src/app.ts',
      'src/lib/util.ts',
    ]);

    expect(resolveFilePath('src\\app.ts')).toBe('src/app.ts');
    expect(resolveFilePath('src/lib/util.ts')).toBe('src/lib/util.ts');
  });

  it('prefers an exact export-path match over a suffix-only candidate', () => {
    const resolveFilePath = createExportFilePathResolver([
      'app.ts',
      'src/app.ts',
    ]);

    expect(resolveFilePath('src\\app.ts')).toBe('src/app.ts');
    expect(resolveFilePath('/workspace/project/app.ts')).toBe('app.ts');
  });

  it('resolves nested absolute paths to the exported path suffix and falls back to normalized paths', () => {
    const resolveFilePath = createExportFilePathResolver([
      'src/app.ts',
      'src/lib/util.ts',
    ]);

    expect(resolveFilePath('/workspace/project/src/lib/util.ts')).toBe('src/lib/util.ts');
    expect(resolveFilePath('C:\\workspace\\project\\src\\app.ts')).toBe('src/app.ts');
    expect(resolveFilePath('src/unknown.ts')).toBe('src/unknown.ts');
  });
});

import { describe, expect, it } from 'vitest';
import {
  normalizeRelationFilePaths,
  relationSortKey,
  sortRelations,
} from '../../../../src/extension/export/symbols/build/relations';

describe('extension/export/symbols/build/relations', () => {
  it('builds stable relation sort keys from file and symbol coordinates', () => {
    expect(
      relationSortKey({
        fromFilePath: 'src/a.ts',
        kind: 'call',
        toFilePath: 'src/b.ts',
        fromSymbolId: 'a#run',
        toSymbolId: 'b#boot',
      } as never),
    ).toBe('src/a.ts:call:src/b.ts:a#run:b#boot');

    expect(
      relationSortKey({
        fromFilePath: 'src/a.ts',
        kind: 'import',
      } as never),
    ).toBe('src/a.ts:import:::');
  });

  it('sorts relations by their normalized keys without mutating the input', () => {
    const relations = [
      { fromFilePath: 'src/b.ts', kind: 'call', toFilePath: 'src/c.ts' },
      { fromFilePath: 'src/a.ts', kind: 'import', toFilePath: 'src/b.ts' },
      { fromFilePath: 'src/a.ts', kind: 'call', toFilePath: 'src/b.ts', fromSymbolId: 'run' },
    ] as never[];

    const sorted = sortRelations(relations);

    expect(sorted).toEqual([
      relations[2],
      relations[1],
      relations[0],
    ]);
    expect(relations).toEqual([
      { fromFilePath: 'src/b.ts', kind: 'call', toFilePath: 'src/c.ts' },
      { fromFilePath: 'src/a.ts', kind: 'import', toFilePath: 'src/b.ts' },
      { fromFilePath: 'src/a.ts', kind: 'call', toFilePath: 'src/b.ts', fromSymbolId: 'run' },
    ]);
  });

  it('normalizes relation file paths and preserves missing destinations', () => {
    expect(
      normalizeRelationFilePaths(
        {
          fromFilePath: 'src/a.ts',
          toFilePath: 'src/b.ts',
          kind: 'call',
        } as never,
        (filePath) => `/workspace/${filePath}`,
      ),
    ).toEqual(
      expect.objectContaining({
        fromFilePath: '/workspace/src/a.ts',
        toFilePath: '/workspace/src/b.ts',
      }),
    );

    expect(
      normalizeRelationFilePaths(
        {
          fromFilePath: 'src/a.ts',
          kind: 'call',
        } as never,
        (filePath) => `/workspace/${filePath}`,
      ),
    ).toEqual(
      expect.objectContaining({
        fromFilePath: '/workspace/src/a.ts',
        toFilePath: undefined,
      }),
    );
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import {
  decodeBase64DataUrl,
  saveExportBuffer,
  toErrorMessage,
} from '../../../src/extension/export/fileSave';

describe('export common', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    Object.defineProperty(vscode.window, 'showSaveDialog', {
      configurable: true,
      value: vi.fn(),
    });
    Object.defineProperty(vscode.window, 'showInformationMessage', {
      configurable: true,
      value: vi.fn(),
    });
    Object.defineProperty(vscode.workspace.fs, 'writeFile', {
      configurable: true,
      value: vi.fn(),
    });
    Object.defineProperty(vscode.commands, 'executeCommand', {
      configurable: true,
      value: vi.fn(),
    });

    Object.defineProperty(vscode.workspace, 'workspaceFolders', {
      get: () => [{ uri: vscode.Uri.file('/workspace'), name: 'workspace', index: 0 }],
      configurable: true,
    });
  });

  it('returns the message from Error instances', () => {
    expect(toErrorMessage(new Error('disk full'))).toBe('disk full');
  });

  it('stringifies non-Error values', () => {
    expect(toErrorMessage({ reason: 'bad data' })).toBe('[object Object]');
  });

  it('decodes base64 export data after validating the prefix', () => {
    const encoded = Buffer.from('hello world').toString('base64');

    expect(decodeBase64DataUrl(`data:text/plain;base64,${encoded}`, 'data:text/plain;base64,')).toEqual(
      Buffer.from('hello world')
    );
  });

  it('throws when the export data url prefix is unexpected', () => {
    expect(() =>
      decodeBase64DataUrl('data:image/png;base64,AAAA', 'data:image/jpeg;base64,')
    ).toThrow('Unexpected export data format. Expected prefix: data:image/jpeg;base64,');
  });

  it('uses the first workspace folder to seed the save dialog and opens the saved file when requested', async () => {
    const saveUri = vscode.Uri.file('/workspace/graph.json');
    vi.mocked(vscode.window.showSaveDialog).mockResolvedValue(saveUri);
    vi.mocked(vscode.window.showInformationMessage).mockResolvedValue('Open File' as never);

    await saveExportBuffer(Buffer.from('graph-data'), {
      defaultFilename: 'graph.json',
      filters: { JSON: ['json'] },
      title: 'Export Graph',
      successMessage: 'Graph exported',
    });

    expect(vscode.window.showSaveDialog).toHaveBeenCalledWith({
      defaultUri: { fsPath: '/workspace/graph.json', path: '/workspace/graph.json' },
      filters: { JSON: ['json'] },
      saveLabel: 'Export',
      title: 'Export Graph',
    });
    expect(vscode.workspace.fs.writeFile).toHaveBeenCalledWith(saveUri, Buffer.from('graph-data'));
    expect(vscode.window.showInformationMessage).toHaveBeenCalledWith(
      'Graph exported to /workspace/graph.json',
      'Open File',
      'Open Folder'
    );
    expect(vscode.commands.executeCommand).toHaveBeenCalledWith('vscode.open', saveUri);
  });

  it('falls back to a plain file uri when no workspace folder exists', async () => {
    Object.defineProperty(vscode.workspace, 'workspaceFolders', {
      get: () => undefined,
      configurable: true,
    });
    vi.mocked(vscode.window.showSaveDialog).mockResolvedValue(undefined);

    await saveExportBuffer(Buffer.from('graph-data'), {
      defaultFilename: 'graph.json',
      filters: { JSON: ['json'] },
      title: 'Export Graph',
      successMessage: 'Graph exported',
    });

    expect(vscode.window.showSaveDialog).toHaveBeenCalledWith({
      defaultUri: { fsPath: 'graph.json', path: 'graph.json' },
      filters: { JSON: ['json'] },
      saveLabel: 'Export',
      title: 'Export Graph',
    });
  });

  it('falls back to a plain file uri when the workspace folder list is empty', async () => {
    Object.defineProperty(vscode.workspace, 'workspaceFolders', {
      get: () => [],
      configurable: true,
    });
    vi.mocked(vscode.window.showSaveDialog).mockResolvedValue(undefined);

    await saveExportBuffer(Buffer.from('graph-data'), {
      defaultFilename: 'graph.json',
      filters: { JSON: ['json'] },
      title: 'Export Graph',
      successMessage: 'Graph exported',
    });

    expect(vscode.window.showSaveDialog).toHaveBeenCalledWith({
      defaultUri: { fsPath: 'graph.json', path: 'graph.json' },
      filters: { JSON: ['json'] },
      saveLabel: 'Export',
      title: 'Export Graph',
    });
  });

  it('does nothing after the save dialog is cancelled', async () => {
    vi.mocked(vscode.window.showSaveDialog).mockResolvedValue(undefined);

    await saveExportBuffer(Buffer.from('graph-data'), {
      defaultFilename: 'graph.json',
      filters: { JSON: ['json'] },
      title: 'Export Graph',
      successMessage: 'Graph exported',
    });

    expect(vscode.workspace.fs.writeFile).not.toHaveBeenCalled();
    expect(vscode.window.showInformationMessage).not.toHaveBeenCalled();
    expect(vscode.commands.executeCommand).not.toHaveBeenCalled();
  });

  it('reveals the saved file in the OS when the folder action is selected', async () => {
    const saveUri = vscode.Uri.file('/workspace/graph.json');
    vi.mocked(vscode.window.showSaveDialog).mockResolvedValue(saveUri);
    vi.mocked(vscode.window.showInformationMessage).mockResolvedValue('Open Folder' as never);

    await saveExportBuffer(Buffer.from('graph-data'), {
      defaultFilename: 'graph.json',
      filters: { JSON: ['json'] },
      title: 'Export Graph',
      successMessage: 'Graph exported',
    });

    expect(vscode.commands.executeCommand).toHaveBeenCalledWith('revealFileInOS', saveUri);
  });

  it('does not run a command when the success action is unrecognized', async () => {
    const saveUri = vscode.Uri.file('/workspace/graph.json');
